+        bottlenecks.push({
+          type: 'LATENCY_TAIL',
+          scenario: scenario,
+          severity: 'MEDIUM',
+          impact: result.latency.p99 / result.latency.p50,
+          details: result.latency
+        });
+      }
+      
+      // Resource bottlenecks
+      if (result.resourceUsage && result.resourceUsage.bottlenecks.length > 0) {
+        bottlenecks.push({
