+          await this.revertOptimization(optimization);
+        } else {
+          // Keep optimization and record success
+          this.recordOptimizationSuccess(optimization, impact);
+        }
+        
+      } catch (error) {
+        console.error(`Failed to apply optimization:`, error);
+        await this.revertOptimization(optimization);
+      }
+    }
+  }
